   230→/**
   231→ * Score a single subtype based on its rule-based classification patterns
   232→ */
   233→function scoreSubtype(
   234→  email: EmailMessage,
   235→  subtypeData: SubtypeDefinition,
   236→  subtypeCode: string,
   237→  tuningParams: RuleScoringStageConfig['tuningParameters']
   238→): SubtypeScore {
   239→  const ruleClassification = subtypeData.ruleBasedClassification || {};
   240→  const matches: RuleScoringMatch[] = [];
   241→
   242→  // Process each confidence tier with bounded aggregation
   243→  const confidenceTiers: Array<{
   244→    tier: keyof SubtypeRuleClassification;
   245→    multiplier: number;
   246→    maxMatches: number;
   247→  }> = [
   248→    { tier: 'highConfidence', multiplier: 1.0, maxMatches: tuningParams.KHigh },
   249→    { tier: 'mediumConfidence', multiplier: tuningParams.M_medium, maxMatches: tuningParams.KMedium },
   250→    { tier: 'lowConfidence', multiplier: tuningParams.M_low, maxMatches: tuningParams.KLow },
   251→  ];
   252→
   253→  let totalScore = 0;
   254→
   255→  for (const { tier, multiplier, maxMatches } of confidenceTiers) {
   256→    const tierRules = ruleClassification[tier] || [];
   257→    const tierMatches: RuleScoringMatch[] = [];
   258→
   259→    for (const rule of tierRules) {
   260→      const match = matchRulePattern(email, rule);
   261→
   262→      if (match.matched) {
   263→        tierMatches.push({
   264→          tier,
   265→          field: rule.field,
   266→          operation: rule.operation,
   267→          values: rule.values || [],
   268→          weight: rule.weight,
   269→          matchedValue: match.matchedValue,
   270→          ruleId: `${subtypeCode}_${tier}_${tierMatches.length}`,
   271→          ruleWeight: rule.weight, // For compatibility with RuleMatch base interface
   272→          partialMatch: false, // For compatibility with RuleMatch base interface
   273→        });
   274→
   275→        console.log(`Rule match - ${tier} in ${rule.field}: "${match.matchedValue}" (weight: ${rule.weight})`);
   276→      }
   277→    }
   278→
   279→    // Apply bounded aggregation - take top K matches for this tier
   280→    const topMatches = tierMatches.sort((a, b) => b.weight - a.weight).slice(0, maxMatches);
   281→
   282→    // Add to total score and matches
   283→    for (const match of topMatches) {
   284→      totalScore += match.weight * multiplier;
   285→      matches.push(match);
   286→    }
   287→  }
   288→
   289→  return {
   290→    totalScore,
   291→    ruleMatches: matches,
   292→    aggregationBreakdown: matches.length > 0 ? matches.map((m) => `${m.tier}:${m.weight}`).join(',') : 'noMatches',
   293→  };
   294→}
   295→
   296→/**
   297→ * Calculate bounded aggregation score to prevent inflation
   298→ * Uses diminishing returns: primary subtype + dampened tail support
   299→ */
   300→function calculateBoundedAggregation(
   301→  subtypeScores: Record<string, SubtypeScore>,
   302→  tuningParams: RuleScoringStageConfig['tuningParameters']
   303→): { totalScore: number; breakdown: string } {
   304→  const scores = Object.entries(subtypeScores)
   305→    .map(([subtype, data]) => ({ subtype, score: data.totalScore }))
   306→    .sort((a, b) => b.score - a.score); // Sort by score descending
   307→
   308→  if (scores.length === 0) {
   309→    return { totalScore: 0, breakdown: 'noSubtypes' };
   310→  }
   311→
   312→  // Primary subtype (highest score) contributes fully
   313→  const primaryScore = scores[0].score;
   314→  const primarySubtype = scores[0].subtype;
   315→
   316→  // Tail support: additional subtypes contribute with diminishing returns
   317→  let tailSupport = 0;
   318→  const tailContributions: string[] = [];
   319→
   320→  if (scores.length > 1) {
   321→    const tailScores = scores.slice(1);
   322→
   323→    for (const tail of tailScores) {
   324→      const contribution = tail.score * tuningParams.TAIL_DAMPEN;
   325→      tailSupport += contribution;
   326→      tailContributions.push(`${tail.subtype}:${contribution.toFixed(1)}`);
   327→    }
   328→
   329→    // Apply tail ratio cap
   330→    const maxTailSupport = primaryScore * tuningParams.TAIL_RATIO_CAP;
   331→    tailSupport = Math.min(tailSupport, maxTailSupport);
   332→  }
   333→
   334→  const totalScore = primaryScore + tailSupport;
   335→  const breakdown =
   336→    `primary:${primarySubtype}:${primaryScore}` +
   337→    (tailSupport > 0 ? ` + tail:${tailSupport.toFixed(1)}(${tailContributions.join(',')})` : '');
   338→
   339→  return { totalScore, breakdown };
   340→}
   341→
   342→/**
   343→ * Calculate confidence percentage based on score and number of matches
   344→ */
   345→function calculateConfidence(score: number, numMatches: number): number {
   346→  if (score === 0) return 0;
   347→
   348→  // Basic confidence calculation: higher scores and more matches = higher confidence
   349→  // Cap at 95% to leave room for AI enhancement
   350→  const baseConfidence = Math.min(score * 5, 80); // 5% per point, max 80%
   351→  const matchBonus = Math.min(numMatches * 3, 15); // 3% per match, max 15%
   352→
   353→  return Math.min(baseConfidence + matchBonus, 95);
   354→}
   355→
   356→/**
   357→ * Select the best subtype based on scores
   358→ */
   359→function selectBestSubtype(subtypeScores: Record<string, SubtypeScore>): string | null {
   360→  if (!subtypeScores || Object.keys(subtypeScores).length === 0) {
   361→    return null;
   362→  }
   363→
   364→  // Find subtype with highest score
   365→  let bestSubtype: string | null = null;
   366→  let bestScore = -1;
   367→
   368→  for (const [subtypeId, scoreData] of Object.entries(subtypeScores)) {
   369→    const score = scoreData?.totalScore || 0;
   370→    if (score > bestScore) {
   371→      bestScore = score;
   372→      bestSubtype = subtypeId;
   373→    }
   374→  }
   375→
   376→  return bestScore > 0 ? bestSubtype : null;
   377→}
