     1→/**
     2→ * Email Utilities
     3→ *
     4→ * Business-logic-agnostic utility functions for email processing.
     5→ * These functions are reused across multiple classification stages.
     6→ */
     7→
     8→/**
     9→ * Extract domain from email address
    10→ * @param email Email address (e.g., "user@example.com")
    11→ * @returns Domain portion (e.g., "example.com") in lowercase
    12→ */
    13→export function extractDomainFromEmail(email: string): string {
    14→  const atIndex = email.lastIndexOf('@');
    15→  if (atIndex === -1) {
    16→    return email; // Invalid email, return as-is
    17→  }
    18→  return email.substring(atIndex + 1).toLowerCase();
    19→}
    20→
    21→/**
    22→ * Check if email domain matches configured domain
    23→ * Supports exact matches and subdomain matching
    24→ *
    25→ * @param emailDomain Domain from email address (should be lowercase)
    26→ * @param configDomain Domain from configuration
    27→ * @returns True if domains match
    28→ *
    29→ * @example
    30→ * domainMatches("chase.com", "chase.com") // true - exact match
    31→ * domainMatches("noreply.chase.com", "chase.com") // true - subdomain match
    32→ * domainMatches("chase.net", "chase.com") // false - different domain
    33→ */
    34→export function domainMatches(emailDomain: string, configDomain: string): boolean {
    35→  const emailDomainLower = emailDomain.toLowerCase();
    36→  const configDomainLower = configDomain.toLowerCase();
    37→
    38→  // Exact match
    39→  if (emailDomainLower === configDomainLower) {
    40→    return true;
    41→  }
    42→
    43→  // Subdomain match (e.g., noreply.chase.com matches chase.com)
    44→  if (emailDomainLower.endsWith('.' + configDomainLower)) {
    45→    return true;
    46→  }
    47→
    48→  return false;
    49→}
    50→
    51→/**
    52→ * Extract plain text from HTML content
    53→ * Removes HTML tags, scripts, styles, and normalizes whitespace.
    54→ * For production use, consider using a proper HTML parser like jsdom or cheerio.
    55→ *
    56→ * @param html HTML content
    57→ * @returns Plain text content with normalized whitespace
    58→ *
    59→ * @example
    60→ * extractTextFromHtml("<p>Hello <b>world</b>!</p>") // "Hello world!"
    61→ * extractTextFromHtml("<div>Line 1<br>Line 2</div>") // "Line 1 Line 2"
    62→ */
    63→export function extractTextFromHtml(html: string): string {
    64→  return html
    65→    .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, ' ') // Remove script tags and content (add space)
    66→    .replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi, ' ') // Remove style tags and content (add space)
    67→    .replace(/<[^>]*>/g, ' ') // Remove all HTML tags (add space)
    68→    .replace(/&nbsp;/g, ' ') // Replace non-breaking spaces with regular spaces
    69→    .replace(/&lt;/g, '<') // Replace common HTML entities
    70→    .replace(/&gt;/g, '>')
    71→    .replace(/&amp;/g, '&')
    72→    .replace(/&quot;/g, '"')
    73→    .replace(/&#39;/g, "'")
    74→    .replace(/&[^;]+;/g, '') // Remove any remaining HTML entities
    75→    .replace(/\s+/g, ' ') // Normalize all whitespace to single spaces
    76→    .trim();
    77→}
    78→
    79→/**
    80→ * Extract body text from email message
    81→ * Prefers plain text body, falls back to extracting text from HTML body.
    82→ * This function standardizes body text extraction across all classification stages.
    83→ *
    84→ * @param email Email message object with bodyPlain and/or bodyHtml fields
    85→ * @returns Extracted body text (plain or from HTML), empty string if no body content
    86→ *
    87→ * @example
    88→ * // With plain text
    89→ * extractEmailBodyText({ bodyPlain: "Hello", bodyHtml: "<p>World</p>" }) // "Hello"
    90→ *
    91→ * // HTML only
    92→ * extractEmailBodyText({ bodyHtml: "<p>Hello world</p>" }) // "Hello world"
    93→ *
    94→ * // No body content
    95→ * extractEmailBodyText({}) // ""
    96→ */
    97→export function extractEmailBodyText(email: { bodyPlain?: string; bodyHtml?: string }): string {
    98→  // Prefer plain text body
    99→  if (email.bodyPlain) {
   100→    return email.bodyPlain.trim();
   101→  }
   102→
   103→  // Fall back to extracting text from HTML
   104→  if (email.bodyHtml) {
   105→    return extractTextFromHtml(email.bodyHtml);
   106→  }
   107→
   108→  // No body content available
   109→  return '';
   110→}
   111→
   112→/**
   113→ * Find matching domain in domain lookup based on confidence level
   114→ * Used by both hard assertions and strong indicators stages
   115→ *
   116→ * @param emailDomain Domain from email address
   117→ * @param domainGroup Domain group configuration with confidence levels
   118→ * @param confidence Confidence level to check ('high' or 'medium')
   119→ * @returns Matching domain object or null if no match found
   120→ */
   121→export function findMatchingDomain(
   122→  emailDomain: string,
   123→  domainGroup: {
   124→    highConfidence: Array<{ domain: string; type?: string }>;
   125→    mediumConfidence: Array<{ domain: string; type?: string }>;
   126→    lowConfidence: Array<{ domain: string; type?: string }>;
   127→  },
   128→  confidence: 'high' | 'medium' | 'low'
   129→): { domain: string; type?: string } | null {
   130→  // Check appropriate confidence level
   131→  const domainsToCheck = confidence === 'high' ? domainGroup.highConfidence : domainGroup.mediumConfidence;
   132→
   133→  return domainsToCheck.find((d) => domainMatches(emailDomain, d.domain)) || null;
   134→}
   135→
   136→/**
   137→ * Check if text contains any of the specified keywords (case-insensitive)
   138→ *
   139→ * @param text Text to search in
   140→ * @param keywords Array of keywords to search for
   141→ * @returns Array of matched keywords (in original case), empty if no matches
   142→ *
   143→ * @example
   144→ * findMatchingKeywords("Invoice #123 due", ["invoice", "receipt"]) // ["invoice"]
   145→ * findMatchingKeywords("Hello world", ["payment", "bill"]) // []
   146→ */
   147→export function findMatchingKeywords(text: string, keywords: string[]): string[] {
   148→  if (!text || !keywords || keywords.length === 0) {
   149→    return [];
   150→  }
   151→
   152→  const textLower = text.toLowerCase();
   153→  const matches: string[] = [];
   154→
   155→  for (const keyword of keywords) {
   156→    if (textLower.includes(keyword.toLowerCase())) {
   157→      matches.push(keyword);
   158→    }
   159→  }
   160→
   161→  return matches;
   162→}
   163→
   164→/**
   165→ * Check if text starts with any of the specified prefixes (case-insensitive)
   166→ *
   167→ * @param text Text to check
   168→ * @param prefixes Array of prefixes to check for
   169→ * @returns First matching prefix (in original case) or null if no match
   170→ *
   171→ * @example
   172→ * findMatchingPrefix("Invoice #123", ["invoice", "receipt"]) // "invoice"
   173→ * findMatchingPrefix("Hello world", ["payment", "bill"]) // null
   174→ */
   175→export function findMatchingPrefix(text: string, prefixes: string[]): string | null {
   176→  if (!text || !prefixes || prefixes.length === 0) {
   177→    return null;
   178→  }
   179→
   180→  const textLower = text.toLowerCase();
   181→
   182→  for (const prefix of prefixes) {
   183→    if (textLower.startsWith(prefix.toLowerCase())) {
   184→      return prefix;
   185→    }
   186→  }
   187→
   188→  return null;
   189→}
   190→
   191→/**
   192→ * Validate email address format (basic validation)
   193→ * For production use, consider using a more comprehensive email validation library
   194→ *
   195→ * @param email Email address to validate
   196→ * @returns True if email appears to be valid format
   197→ */
   198→export function isValidEmailFormat(email: string): boolean {
   199→  // Basic email format validation
   200→  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
   201→  return emailRegex.test(email);
   202→}
   203→
   204→/**
   205→ * Normalize email address for comparison
   206→ * Converts to lowercase and trims whitespace
   207→ *
   208→ * @param email Email address to normalize
   209→ * @returns Normalized email address
   210→ */
   211→export function normalizeEmail(email: string): string {
   212→  return email.trim().toLowerCase();
   213→}
