 *
 * @param emailDomain Domain from email address
 * @param domainGroup Domain group configuration with confidence levels
 * @param confidence Confidence level to check ('high' or 'medium')
 * @returns Matching domain object or null if no match found
 */
export function findMatchingDomain(
  emailDomain: string,
  domainGroup: {
    highConfidence: Array<{ domain: string; type?: string }>;
    mediumConfidence: Array<{ domain: string; type?: string }>;
    lowConfidence: Array<{ domain: string; type?: string }>;
  },
  confidence: 'high' | 'medium' | 'low'
): { domain: string; type?: string } | null {
  // Check appropriate confidence level
  const domainsToCheck = confidence === 'high' ? domainGroup.highConfidence : domainGroup.mediumConfidence;

  return domainsToCheck.find((d) => domainMatches(emailDomain, d.domain)) || null;
}

