import { z } from 'zod';

/**
 * Zod schema for CategoryConfiguration validation
 * Validates structure per ${repoRoot}/docs/SCORING_LOGIC.md "Tuning Parameters Summary" section
 */

// Base validation schemas for reusability
const EmailAddressSchema = z.string().email();
const DomainSchema = z.string().regex(/^[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}$/, 'Invalid domain format');
const ConfidenceSchema = z.string().regex(/^(high|medium|low)$/, 'Must be high, medium, or low');
const WeightSchema = z.number().min(0).max(1);
const ThresholdSchema = z.number().min(0).max(1);

// Rule pattern validation
export const RulePatternSchema = z.object({
  field: z.enum(['subject', 'body', 'from.address', 'from.name', 'to', 'headers']),
  operation: z.enum(['containsAny', 'startsWith', 'endsWith', 'regexAny', 'exists', 'notContains']),
  values: z.array(z.string()).optional(),
  weight: WeightSchema,
});

// Attribute schemas
const AttributeRoleSchema = z.enum([
  'CORE',
  'PRIMARY_BOOST',
  'SECONDARY_BOOST',
  'DISAMBIGUATOR',
  'FILTER',
  'STRUCTURAL',
  'DERIVED_LINK',
  'NEUTRAL',
]);

const AttributeSchemaDefinition = z.object({
  type: z.enum(['enum', 'boolean', 'string', 'number']),
  values: z.array(z.string()).optional(),
  description: z.string(),
  validation: z
    .object({
      required: z.boolean().default(false),
      min: z.number().optional(),
      max: z.number().optional(),
      pattern: z.string().optional(),
    })
    .optional(),
});

const AttributeDetectorSchema = z.object({
  attribute: z.string(),
  field: z.string(),
  operation: z.string(),
  values: z.array(z.string()),
  confidence: z.number().min(0).max(1).default(1.0),
  parallelSafe: z.boolean().default(true),
});

const DerivedAttributeSchema = z.object({
  logic: z.string(),
  notes: z.string(),
  dependencies: z.array(z.string()).default([]),
  parallelSafe: z.boolean().default(false),
});

// Domain reference schemas
const DomainReferenceSchema = z.object({
  sourceGroup: z.string(),
  confidence: ConfidenceSchema,
});

// Category signal schemas
const HardAssertionsSchema = z.object({
  fromDomainsRef: DomainReferenceSchema.optional(),
  subjectPrefixes: z.array(z.string()).optional(),
  fromAddresses: z.array(EmailAddressSchema).optional(),
  customRules: z.array(RulePatternSchema).optional(),
});

const StrongIndicatorsSchema = z.object({
  fromDomainsRef: DomainReferenceSchema.optional(),
  subjectContains: z.array(z.string()).optional(),
  bodyContains: z.array(z.string()).optional(),
  customRules: z.array(RulePatternSchema).optional(),
  diminishingReturns: z
    .object({
      enabled: z.boolean().default(true),
      decayFactor: z.number().min(0).max(1).default(0.8),
      maxIndicators: z.number().int().min(1).default(5),
    })
    .optional(),
});

const DisambiguatorsSchema = z.object({
  boostIfPresentAttributes: z.array(z.string()).optional(),
  suppressIfBodyContains: z.array(z.string()).optional(),
  boostIfAbsentCategories: z.array(z.string()).optional(),
  pairwiseAdjustments: z
    .array(
      z.object({
        targetCategory: z.string(),
        condition: z.string(),
        adjustment: z.number().min(-1).max(1),
        reason: z.string(),
      })
    )
    .optional(),
});

const CategorySignalsSchema = z.object({
  hardAssertions: HardAssertionsSchema.optional(),
  strongIndicators: StrongIndicatorsSchema.optional(),
  disambiguators: DisambiguatorsSchema.optional(),
  validation: z
    .object({
      requiredFields: z.array(z.string()).default([]),
      mutuallyExclusive: z.array(z.array(z.string())).default([]),
    })
    .optional(),
});

const ActionSchema = z.object({
  gmailLabel: z.string().nullable(),
  archive: z.boolean(),
  markAsRead: z.boolean(),
  autoDelete: z.boolean(),
  customActions: z.array(z.string()).optional(),
});

// Subtype definition schema
const SubtypeDefinitionSchema = z.object({
  description: z.string(),
  actions: ActionSchema.optional(),
  ruleBasedClassification: z
    .object({
      highConfidence: z.array(RulePatternSchema).optional(),
      mediumConfidence: z.array(RulePatternSchema).optional(),
      lowConfidence: z.array(RulePatternSchema).optional(),
    })
    .optional(),
  derived: z.boolean().default(false),
  derivationLogic: z.string().optional(),
  parallelSafe: z.boolean().default(true),
  tuningParameters: z
    .object({
      KHigh: z.number().min(0).default(1.0),
      KMedium: z.number().min(0).default(0.7),
      KLow: z.number().min(0).default(0.3),
      maxRuleScore: z.number().min(0).default(1.0),
    })
    .optional(),
});

// Top level category schema
const TopLevelCategorySchema = z.object({
  description: z.string(),
  actions: ActionSchema.optional(),
  subtypes: z.record(z.string(), SubtypeDefinitionSchema),
  aiFinalClassification: z.object({
    categoryDescription: z.string(),
    decisionCriteria: z.array(z.string()),
    exclusionCriteria: z.array(z.string()).optional(),
    promptTemplate: z.string().optional(),
  }),
  tuningParameters: z
    .object({
      confidenceBoost: z.number().min(0).max(1).default(0),
      priorityWeight: z.number().min(0).max(2).default(1.0),
      maxScoreCap: z.number().min(0).default(1.0),
    })
    .optional(),
});

// Processing settings schema
const ProcessingSettingsSchema = z.object({
  initialization: z.object({
    applyHardAssertions: z.boolean().default(true),
    seedCategoryScores: z.boolean().default(true),
    parallelInitialization: z.boolean().default(true).optional(),
  }),
  ruleScoring: z.object({
    useLexicalPatterns: z.boolean().default(true),
    applySubtypeRules: z.boolean().default(true),
    boundedAggregation: z.boolean().default(true),
    parallelRuleEvaluation: z.boolean().default(true).optional(),
    tuningParameters: z
      .object({
        KHigh: z.number().min(0).default(1.0),
        KMedium: z.number().min(0).default(0.7),
        KLow: z.number().min(0).default(0.3),
        M_medium: z.number().min(0).max(1).default(0.7),
        M_low: z.number().min(0).max(1).default(0.3),
        TAIL_DAMPEN: z.number().min(0).max(1).default(0.5),
        TAIL_RATIO_CAP: z.number().min(0).max(1).default(0.3),
        aggregationCap: z.number().min(0).default(1.0),
      })
      .optional(),
  }),
  attributeProcessing: z.object({
    detectSelfSent: z.boolean().default(true),
    resolveDomains: z.boolean().default(true),
    deriveContextFlags: z.boolean().default(true),
    parallelDetection: z.boolean().default(true).optional(),
    cacheAttributeResults: z.boolean().default(true).optional(),
  }),
  attributeInfluence: z.object({
    applyBonuses: z.boolean().default(true),
    applyPenalties: z.boolean().default(true),
    enforceCaps: z.boolean().default(true),
    parallelInfluenceCalculation: z.boolean().default(true).optional(),
    tuningParameters: z
      .object({
        bonusMultiplier: z.number().min(0).default(1.0),
        penaltyMultiplier: z.number().min(0).default(1.0),
        maxTotalBonus: z.number().min(0).default(0.5),
        maxTotalPenalty: z.number().min(0).default(0.3),
      })
      .optional(),
  }),
  strongIndicators: z
    .object({
      baseWeight: z.number().min(0).default(10).optional(),
      diminishingReturnsFactor: z.number().min(0).max(1).default(0.5).optional(),
    })
    .optional(),
  disambiguation: z
    .object({
      pairwiseAdjustments: z.boolean().default(true),
      confidenceGapThreshold: ThresholdSchema.default(0.1),
      maxAdjustmentsPerCategory: z.number().int().min(1).default(3).optional(),
    })
    .optional(),
  multiLabelSelection: z.object({
    maxLabels: z.number().int().min(1).default(3),
    minSecondaryConfidence: ThresholdSchema.default(0.6),
    allowedCombinations: z
      .array(
        z.object({
          categories: z.array(z.string()),
          maxConfidenceSum: z.number().min(0).default(2.0).optional(),
          notes: z.string().optional(),
        })
      )
      .default([]),
    confidenceGapMinimum: z.number().min(0).default(0.15),
  }),
  aiRouting: z.object({
    highConfidenceThreshold: ThresholdSchema.default(0.8),
    aiRequiredThreshold: ThresholdSchema.default(0.4),
    skipAiConditions: z.array(z.string()).default([]),
    batchSize: z.number().int().min(1).default(10).optional(),
    timeoutMs: z.number().int().min(1000).default(30000).optional(),
  }),
  performance: z
    .object({
      parallelProcessing: z.boolean().default(true),
      maxParallelEmails: z.number().int().min(1).default(10),
      batchSize: z.number().int().min(1).default(50),
      enableCaching: z.boolean().default(true),
      cacheTtlSeconds: z.number().int().min(60).default(3600),
    })
    .optional(),
});

// Confidence thresholds schema
export const ConfidenceThresholdsSchema = z.object({
  highConfidence: ThresholdSchema.default(0.8),
  mediumConfidence: ThresholdSchema.default(0.6),
  lowConfidence: ThresholdSchema.default(0.4),
  aiClassificationRequired: ThresholdSchema.default(0.4),
  manualReviewRequired: ThresholdSchema.default(0.2),
  secondaryLabelMinGap: z.number().min(0).default(0.15),
  tuningParameters: z
    .object({
      confidenceDecayFactor: z.number().min(0).max(1).default(0.95),
      uncertaintyPenalty: z.number().min(0).max(0.5).default(0.1),
    })
    .optional(),
});

// Multi-label policy schema
const MultiLabelPolicySchema = z.object({
  maxTopLevelLabels: z.number().int().min(1).default(3),
  minConfidenceForAdditional: ThresholdSchema.default(0.6),
  allowFinancialActionableCopresence: z.boolean().default(false),
  allowedCombinations: z
    .array(
      z.object({
        categories: z.array(z.string()),
        maxConfidenceSum: z.number().min(0).default(2.0),
        notes: z.string().optional(),
      })
    )
    .default([]),
  exclusions: z
    .array(
      z.object({
        categories: z.array(z.string()),
        reason: z.string(),
      })
    )
    .default([]),
});

// Domain overrides schema
const DomainOverridesSchema = z.record(
  z.string(),
  z.object({
    hardInclude: z.array(DomainSchema).default([]),
    hardExclude: z.array(DomainSchema).default([]),
    strongInclude: z.array(DomainSchema).default([]),
    strongExclude: z.array(DomainSchema).default([]),
    notes: z.string().optional(),
  })
);

// Domain resolution schema
const DomainResolutionSchema = z.object({
  mode: z.enum(['runtimeResolved', 'static', 'hybrid']).default('runtimeResolved'),
  source: z.string().default('config/domain-sources.json'),
  notes: z.string().optional(),
  cacheSettings: z
    .object({
      enableCaching: z.boolean().default(true),
      cacheTtlSeconds: z.number().int().min(60).default(3600),
      maxCacheEntries: z.number().int().min(100).default(10000),
    })
    .optional(),
});

// Attribute system schema
const AttributeSystemSchema = z.object({
  schema: z.record(z.string(), AttributeSchemaDefinition),
  detectors: z.array(AttributeDetectorSchema),
  derived: z.record(z.string(), DerivedAttributeSchema),
  attributeBonusMap: z.record(z.string(), z.record(z.string(), z.number())),
  parallelProcessing: z
    .object({
      enableParallelDetection: z.boolean().default(true),
      maxParallelDetectors: z.number().int().min(1).default(5),
      batchDerivedAttributes: z.boolean().default(true),
    })
    .optional(),
});

// Attribute relevance matrix schema
const AttributeRelevanceMatrixSchema = z
  .object({
    _roles_legend: z
      .object({
        CORE: z.string(),
        PRIMARY_BOOST: z.string(),
        SECONDARY_BOOST: z.string(),
        DISAMBIGUATOR: z.string(),
        FILTER: z.string(),
        STRUCTURAL: z.string(),
        DERIVED_LINK: z.string(),
        NEUTRAL: z.string(),
      })
      .optional(),
  })
  .catchall(
    z.union([
      // Category entry with categoryRoles
      z.object({
        categoryRoles: z.record(z.string(), AttributeRoleSchema).optional(),
        subtypes: z
          .record(
            z.string(),
            z.object({
              roles: z.record(z.string(), AttributeRoleSchema),
            })
          )
          .optional(),
        tuningParameters: z
          .object({
            bonusMultipliers: z.record(z.string(), z.number().min(0).default(1.0)),
            penaltyMultipliers: z.record(z.string(), z.number().min(0).default(1.0)),
            maxInfluence: z.number().min(0).default(0.5),
          })
          .optional(),
      }),
      // Legacy RolesLegend entry (for compatibility)
      z.object({
        CORE: z.string(),
        PRIMARY_BOOST: z.string(),
        SECONDARY_BOOST: z.string(),
        DISAMBIGUATOR: z.string(),
        FILTER: z.string(),
        STRUCTURAL: z.string(),
        DERIVED_LINK: z.string(),
        NEUTRAL: z.string(),
      }),
    ])
  );

// AI prompt system schema
const AIPromptSystemSchema = z.object({
  featureExtraction: z.object({
    systemPrompt: z.array(z.string()),
    userPrompt: z.array(z.string()),
    temperature: z.number().min(0).max(2).default(0.1),
    maxTokens: z.number().int().min(100).default(1000),
  }),
  finalClassification: z.object({
    systemPrompt: z.array(z.string()),
    userPrompt: z.array(z.string()),
    temperature: z.number().min(0).max(2).default(0.1),
    maxTokens: z.number().int().min(50).default(500),
  }),
  modelSettings: z
    .object({
      modelName: z.string().default('gpt-4'),
      fallbackModel: z.string().default('gpt-3.5-turbo'),
      requestTimeoutMs: z.number().int().min(1000).default(30000),
      retryAttempts: z.number().int().min(0).default(3),
    })
    .optional(),
});

// JSON Schema validation (for feature extraction schema)
const JSONSchemaSchema = z.object({
  type: z.string(),
  properties: z.record(z.string(), z.any()),
  required: z.array(z.string()),
  additionalProperties: z.boolean().default(false),
  $schema: z.string().optional(),
  title: z.string().optional(),
  description: z.string().optional(),
});

// Main processing config schema
const ProcessingConfigSchema = z.object({
  version: z.number().int().min(1),
  taxonomyNotes: z.string(),
  settings: ProcessingSettingsSchema,
  categorySignals: z.record(z.string(), CategorySignalsSchema),
  confidenceThresholds: ConfidenceThresholdsSchema,
  multiLabelPolicy: MultiLabelPolicySchema,
  domainSignalOverrides: DomainOverridesSchema,
  domainSignalResolution: DomainResolutionSchema,
  topLevelCategories: z.record(z.string(), TopLevelCategorySchema),
  attributes: AttributeSystemSchema,
  attributeRelevance: AttributeRelevanceMatrixSchema,
  aiPrompts: AIPromptSystemSchema,
  featureExtractionSchema: JSONSchemaSchema,
});

// Main category configuration schema
export const CategoryConfigurationSchema = z.object({
  version: z.string().regex(/^\d+\.\d+\.\d+$/, 'Must be semantic version format (x.y.z)'),
  lastModified: z.coerce.date(),
  hash: z.string().length(64, 'Must be SHA-256 hash'),

  // Main processing configuration
  processingConfig: ProcessingConfigSchema,

  // Validation metadata
  schemaVersion: z.string().default('1.0.0'),
  validationPassed: z.boolean(),
  validationErrors: z.array(z.string()).default([]),

  // Runtime optimization (these will be populated by the system)
  compiledRules: z
    .array(
      z.object({
        category: z.string(),
        subtype: z.string(),
        tier: z.enum(['high', 'medium', 'low']),
        pattern: z.any(), // RegExp objects can't be validated by Zod
        weight: z.number(),
        parallelSafe: z.boolean().default(true),
      })
    )
    .optional(),

  attributeMatrix: z
    .record(
      z.string(),
      z.record(
        z.string(),
        z.object({
          role: AttributeRoleSchema,
          bonus: z.number(),
          cap: z.number(),
        })
      )
    )
    .optional(),

  // Performance metadata
  performanceMetrics: z
    .object({
      lastValidationTimeMs: z.number().optional(),
      ruleCompilationTimeMs: z.number().optional(),
      matrixComputationTimeMs: z.number().optional(),
      totalCategories: z.number().int().optional(),
      totalRules: z.number().int().optional(),
      parallelCompatibleRules: z.number().int().optional(),
    })
    .optional(),
});

// Type inference
export type CategoryConfiguration = z.infer<typeof CategoryConfigurationSchema>;
export type ProcessingConfig = z.infer<typeof ProcessingConfigSchema>;
export type ProcessingSettings = z.infer<typeof ProcessingSettingsSchema>;
export type CategorySignals = z.infer<typeof CategorySignalsSchema>;
export type ConfidenceThresholds = z.infer<typeof ConfidenceThresholdsSchema>;
export type AttributeRole = z.infer<typeof AttributeRoleSchema>;
export type RulePattern = z.infer<typeof RulePatternSchema>;
export type TopLevelCategory = z.infer<typeof TopLevelCategorySchema>;
export type SubtypeDefinition = z.infer<typeof SubtypeDefinitionSchema>;
export type AttributeSystem = z.infer<typeof AttributeSystemSchema>;
export type AttributeRelevanceMatrix = z.infer<typeof AttributeRelevanceMatrixSchema>;
export type AIPromptSystem = z.infer<typeof AIPromptSystemSchema>;

// Validation helper functions
export const validateCategoryConfiguration = (config: unknown): CategoryConfiguration => {
  return CategoryConfigurationSchema.parse(config);
};

export const validateProcessingConfig = (config: unknown): ProcessingConfig => {
  return ProcessingConfigSchema.parse(config);
};

// Partial validation for specific sections
export const validateCategorySignals = (signals: unknown): CategorySignals => {
  return CategorySignalsSchema.parse(signals);
};

export const validateAttributeSystem = (system: unknown): AttributeSystem => {
  return AttributeSystemSchema.parse(system);
};

export const validateProcessingSettings = (settings: unknown): ProcessingSettings => {
  return ProcessingSettingsSchema.parse(settings);
};

// Schema validation utilities
export const getSchemaVersion = () => '1.0.0';

export const isValidConfig = (config: unknown): boolean => {
  try {
    CategoryConfigurationSchema.parse(config);
    return true;
  } catch {
    return false;
  }
};

export const getValidationErrors = (config: unknown): string[] => {
  try {
    CategoryConfigurationSchema.parse(config);
    return [];
  } catch (error) {
    if (error instanceof z.ZodError) {
      return error.errors.map((err) => `${err.path.join('.')}: ${err.message}`);
    }
    return ['Unknown validation error'];
  }
};

import { z } from 'zod';

/**
 * Zod schema for ProcessingConfig validation
 * Includes all tuning parameters per ${repoRoot}/docs/SCORING_LOGIC.md throughout
 */

// Base validation schemas
const PositiveNumberSchema = z.number().min(0);
const ProbabilitySchema = z.number().min(0).max(1);
const WeightSchema = z.number().min(0).max(2);
// const IntegerSchema = z.number().int(); // Reserved for future use
const PositiveIntegerSchema = z.number().int().min(1);

// Tuning parameter schemas for individual stages
const HardAssertionTuningSchema = z.object({
  highConfidenceFloor: ProbabilitySchema.default(0.9),
  domainConfidenceBoost: z.number().min(0).max(0.2).default(0.1),
  subjectPrefixBoost: z.number().min(0).max(0.15).default(0.1),
  fromAddressBoost: z.number().min(0).max(0.1).default(0.05),
  parallelProcessingEnabled: z.boolean().default(true),
});

const StrongIndicatorTuningSchema = z.object({
  baseSeedValue: ProbabilitySchema.default(0.6),
  diminishingReturns: z.object({
    enabled: z.boolean().default(true),
    decayFactor: z.number().min(0.1).max(0.9).default(0.8),
    maxIndicators: PositiveIntegerSchema.default(5),
    minimumValueThreshold: z.number().min(0).max(0.1).default(0.05),
  }),
  domainWeightMultiplier: WeightSchema.default(1.2),
  contentWeightMultiplier: WeightSchema.default(1.0),
  parallelSeedingEnabled: z.boolean().default(true),
});

const RuleScoringTuningSchema = z.object({
  // Subtype scoring formula parameters (KHigh, KMedium, KLow)
  KHigh: PositiveNumberSchema.default(1.0),
  KMedium: PositiveNumberSchema.default(0.7),
  KLow: PositiveNumberSchema.default(0.3),

  // Bounded aggregation parameters
  aggregationCap: ProbabilitySchema.default(1.0),
  saturationThreshold: ProbabilitySchema.default(0.95),
  diminishingFactor: z.number().min(0.5).max(1.0).default(0.9),

  // Rule evaluation settings
  lexicalPatternWeight: WeightSchema.default(1.0),
  subtypeRuleWeight: WeightSchema.default(1.0),
  caseSensitivity: z.boolean().default(false),
  wordBoundaryMatching: z.boolean().default(true),

  // Performance optimization
  parallelRuleEvaluation: z.boolean().default(true),
  maxParallelRules: PositiveIntegerSchema.default(10),
  ruleCacheEnabled: z.boolean().default(true),
  cacheSizeLimit: PositiveIntegerSchema.default(1000),
});

const AttributeDetectionTuningSchema = z.object({
  // Detection confidence thresholds
  minimumDetectionConfidence: ProbabilitySchema.default(0.7),
  highConfidenceThreshold: ProbabilitySchema.default(0.9),

  // Attribute-specific settings
  selfSentDetection: z.object({
    enabled: z.boolean().default(true),
    confidenceBoost: z.number().min(0).max(0.2).default(0.1),
    domainWhitelist: z.array(z.string()).default([]),
  }),

  domainResolution: z.object({
    enabled: z.boolean().default(true),
    cacheEnabled: z.boolean().default(true),
    cacheTtlSeconds: PositiveIntegerSchema.default(3600),
    timeoutMs: PositiveIntegerSchema.default(5000),
  }),

  contextFlags: z.object({
    urgencyDetectionEnabled: z.boolean().default(true),
    structuralPatternDetection: z.boolean().default(true),
    temporalSignalDetection: z.boolean().default(true),
  }),

  // Parallel processing
  parallelDetectionEnabled: z.boolean().default(true),
  maxParallelDetectors: PositiveIntegerSchema.default(5),
  detectorTimeoutMs: PositiveIntegerSchema.default(10000),
});

const AttributeInfluenceTuningSchema = z.object({
  // Bonus and penalty application
  bonusMultiplier: WeightSchema.default(1.0),
  penaltyMultiplier: WeightSchema.default(1.0),

  // Influence caps per role type
  coreAttributeMaxInfluence: ProbabilitySchema.default(0.4),
  primaryBoostMaxInfluence: ProbabilitySchema.default(0.3),
  secondaryBoostMaxInfluence: ProbabilitySchema.default(0.2),
  disambiguatorMaxInfluence: ProbabilitySchema.default(0.15),
  filterMaxInfluence: ProbabilitySchema.default(0.1),

  // Total influence limits
  maxTotalBonus: ProbabilitySchema.default(0.5),
  maxTotalPenalty: ProbabilitySchema.default(0.3),

  // Role enforcement
  strictRoleEnforcement: z.boolean().default(true),
  fallbackToNeutralOnConflict: z.boolean().default(true),

  // Parallel processing
  parallelInfluenceCalculation: z.boolean().default(true),
  influenceCacheEnabled: z.boolean().default(true),
});

const DisambiguationTuningSchema = z.object({
  // Pairwise adjustment thresholds
  confidenceGapThreshold: ProbabilitySchema.default(0.1),
  minimumAdjustmentThreshold: z.number().min(0).max(0.1).default(0.02),
  maximumAdjustmentPerPair: ProbabilitySchema.default(0.2),

  // Adjustment limits
  maxAdjustmentsPerCategory: PositiveIntegerSchema.default(3),
  totalAdjustmentCap: ProbabilitySchema.default(0.3),

  // Disambiguation strategies
  pairwiseAdjustmentsEnabled: z.boolean().default(true),
  contextAwareDisambiguation: z.boolean().default(true),
  temporalDisambiguation: z.boolean().default(false),

  // Performance settings
  maxDisambiguationIterations: PositiveIntegerSchema.default(5),
  convergenceThreshold: z.number().min(0).max(0.01).default(0.001),
});

const MultiLabelTuningSchema = z.object({
  // Selection thresholds
  minSecondaryConfidence: ProbabilitySchema.default(0.6),
  confidenceGapMinimum: ProbabilitySchema.default(0.15),
  maxConfidenceSum: PositiveNumberSchema.default(2.0),

  // Label limits
  maxLabels: PositiveIntegerSchema.default(3),
  maxTopLevelLabels: PositiveIntegerSchema.default(2),

  // Co-presence rules
  financialActionableCopresenceAllowed: z.boolean().default(false),
  categoryCombinationPenalties: z.record(z.string(), z.number().min(0).max(0.5)).default({}),

  // Quality controls
  minimumPrimaryLead: ProbabilitySchema.default(0.1),
  secondaryConfidenceDecay: z.number().min(0.5).max(1.0).default(0.9),
  labelCoherenceCheck: z.boolean().default(true),
});

const AIRoutingTuningSchema = z.object({
  // Routing thresholds
  highConfidenceThreshold: ProbabilitySchema.default(0.8),
  aiRequiredThreshold: ProbabilitySchema.default(0.4),
  manualReviewThreshold: ProbabilitySchema.default(0.2),

  // AI service configuration
  modelSettings: z.object({
    primaryModel: z.string().default('gpt-4'),
    fallbackModel: z.string().default('gpt-3.5-turbo'),
    temperature: z.number().min(0).max(2).default(0.1),
    maxTokens: PositiveIntegerSchema.default(500),
    timeoutMs: PositiveIntegerSchema.default(30000),
  }),

  // Batch processing
  batchSize: PositiveIntegerSchema.default(10),
  batchTimeoutMs: PositiveIntegerSchema.default(60000),
  parallelAiRequests: z.boolean().default(true),
  maxParallelRequests: PositiveIntegerSchema.default(5),

  // Skip conditions
  skipAiConditions: z
    .array(
      z.enum([
        'highConfidenceAchieved',
        'singleStrongCategory',
        'hardAssertionMatch',
        'manualReviewFlagged',
        'processingTimeExceeded',
      ])
    )
    .default([]),

  // Quality controls
  aiConfidenceThreshold: ProbabilitySchema.default(0.7),
  consistencyCheckEnabled: z.boolean().default(true),
  fallbackToRuleBased: z.boolean().default(true),
});

const AuditTrailTuningSchema = z.object({
  // Explainability trace configuration
  generateFullTrace: z.boolean().default(true),
  includeStageTimings: z.boolean().default(true),
  includeParallelExecutionMap: z.boolean().default(true),
  includeConfigurationRefs: z.boolean().default(true),

  // Trace detail levels
  ruleEvaluationDetails: z.enum(['minimal', 'standard', 'verbose']).default('standard'),
  attributeDetectionDetails: z.enum(['minimal', 'standard', 'verbose']).default('standard'),
  scoreBreakdownPrecision: PositiveIntegerSchema.default(4),

  // Performance optimization
  traceCompressionEnabled: z.boolean().default(false),
  asyncTraceWriting: z.boolean().default(true),
  traceBatchingEnabled: z.boolean().default(true),
  batchSize: PositiveIntegerSchema.default(50),

  // Retention settings
  traceRetentionDays: PositiveIntegerSchema.default(90),
  archiveOldTraces: z.boolean().default(true),
  compressionAfterDays: PositiveIntegerSchema.default(30),
});

// Performance and parallelism settings
const PerformanceTuningSchema = z.object({
  // Global parallel processing
  parallelProcessingEnabled: z.boolean().default(true),
  maxParallelEmails: PositiveIntegerSchema.default(10),
  emailBatchSize: PositiveIntegerSchema.default(50),

  // Stage-specific parallelism
  parallelStages: z
    .array(
      z.enum(['attributeDetection', 'ruleEvaluation', 'influenceCalculation', 'aiRouting', 'auditTrailGeneration'])
    )
    .default(['attributeDetection', 'ruleEvaluation']),

  // Memory management
  memoryLimitMb: PositiveIntegerSchema.default(512),
  gcThresholdMb: PositiveIntegerSchema.default(256),
  cacheSizeLimits: z.object({
    ruleCacheMb: PositiveIntegerSchema.default(64),
    attributeCacheMb: PositiveIntegerSchema.default(32),
    configCacheMb: PositiveIntegerSchema.default(16),
  }),

  // Timeout settings
  totalProcessingTimeoutMs: PositiveIntegerSchema.default(60000),
  stageTimeoutMs: PositiveIntegerSchema.default(10000),
  databaseTimeoutMs: PositiveIntegerSchema.default(5000),

  // Optimization flags
  enableCaching: z.boolean().default(true),
  enableMemoization: z.boolean().default(true),
  enableLazyLoading: z.boolean().default(true),
  precompileRules: z.boolean().default(true),
});

// Main processing configuration schema with all tuning parameters
export const ProcessingConfigTuningSchema = z.object({
  // Global settings
  version: PositiveIntegerSchema,
  schemaVersion: z.string().default('1.0.0'),
  taxonomyNotes: z.string(),

  // Stage-specific tuning parameters
  hardAssertionTuning: HardAssertionTuningSchema.optional(),
  strongIndicatorTuning: StrongIndicatorTuningSchema.optional(),
  ruleScoringTuning: RuleScoringTuningSchema.optional(),
  attributeDetectionTuning: AttributeDetectionTuningSchema.optional(),
  attributeInfluenceTuning: AttributeInfluenceTuningSchema.optional(),
  disambiguationTuning: DisambiguationTuningSchema.optional(),
  multiLabelTuning: MultiLabelTuningSchema.optional(),
  aiRoutingTuning: AIRoutingTuningSchema.optional(),
  auditTrailTuning: AuditTrailTuningSchema.optional(),

  // Performance and system tuning
  performanceTuning: PerformanceTuningSchema.optional(),

  // Validation settings
  strictValidation: z.boolean().default(true),
  allowExperimentalFeatures: z.boolean().default(false),
  compatibilityMode: z.enum(['strict', 'permissive', 'legacy']).default('strict'),

  // Monitoring and debugging
  monitoring: z
    .object({
      enableMetricsCollection: z.boolean().default(true),
      detailedTiming: z.boolean().default(false),
      memoryTracking: z.boolean().default(false),
      errorTracking: z.boolean().default(true),
      performanceAlerts: z
        .object({
          slowProcessingThresholdMs: PositiveIntegerSchema.default(30000),
          highMemoryThresholdMb: PositiveIntegerSchema.default(256),
          errorRateThreshold: ProbabilitySchema.default(0.05),
        })
        .default({}),
    })
    .default({}),
});

// Simplified schema for basic processing config (backward compatibility)
export const BasicProcessingConfigSchema = z.object({
  version: PositiveIntegerSchema,
  taxonomyNotes: z.string(),

  // Essential settings only
  settings: z.object({
    initialization: z.object({
      applyHardAssertions: z.boolean().default(true),
      seedCategoryScores: z.boolean().default(true),
    }),
    ruleScoring: z.object({
      useLexicalPatterns: z.boolean().default(true),
      applySubtypeRules: z.boolean().default(true),
      boundedAggregation: z.boolean().default(true),
    }),
    attributeProcessing: z.object({
      detectSelfSent: z.boolean().default(true),
      resolveDomains: z.boolean().default(true),
      deriveContextFlags: z.boolean().default(true),
    }),
    disambiguation: z.object({
      pairwiseAdjustments: z.boolean().default(true),
      confidenceGapThreshold: ProbabilitySchema.default(0.1),
    }),
    multiLabelSelection: z.object({
      maxLabels: PositiveIntegerSchema.default(3),
      minSecondaryConfidence: ProbabilitySchema.default(0.6),
    }),
    aiRouting: z.object({
      highConfidenceThreshold: ProbabilitySchema.default(0.8),
      aiRequiredThreshold: ProbabilitySchema.default(0.4),
    }),
  }),

  // Basic performance settings
  performance: z
    .object({
      parallelProcessing: z.boolean().default(true),
      batchSize: PositiveIntegerSchema.default(50),
      timeoutMs: PositiveIntegerSchema.default(60000),
    })
    .default({}),
});

// Type inference
export type ProcessingConfigTuning = z.infer<typeof ProcessingConfigTuningSchema>;
export type BasicProcessingConfig = z.infer<typeof BasicProcessingConfigSchema>;
export type HardAssertionTuning = z.infer<typeof HardAssertionTuningSchema>;
export type StrongIndicatorTuning = z.infer<typeof StrongIndicatorTuningSchema>;
export type RuleScoringTuning = z.infer<typeof RuleScoringTuningSchema>;
export type AttributeDetectionTuning = z.infer<typeof AttributeDetectionTuningSchema>;
export type AttributeInfluenceTuning = z.infer<typeof AttributeInfluenceTuningSchema>;
export type DisambiguationTuning = z.infer<typeof DisambiguationTuningSchema>;
export type MultiLabelTuning = z.infer<typeof MultiLabelTuningSchema>;
export type AIRoutingTuning = z.infer<typeof AIRoutingTuningSchema>;
export type AuditTrailTuning = z.infer<typeof AuditTrailTuningSchema>;
export type PerformanceTuning = z.infer<typeof PerformanceTuningSchema>;

// Validation helper functions
export const validateProcessingConfigTuning = (config: unknown): ProcessingConfigTuning => {
  return ProcessingConfigTuningSchema.parse(config);
};

export const validateBasicProcessingConfig = (config: unknown): BasicProcessingConfig => {
  return BasicProcessingConfigSchema.parse(config);
};

// Tuning parameter validation helpers
export const validateHardAssertionTuning = (tuning: unknown): HardAssertionTuning => {
  return HardAssertionTuningSchema.parse(tuning);
};

export const validateRuleScoringTuning = (tuning: unknown): RuleScoringTuning => {
  return RuleScoringTuningSchema.parse(tuning);
};

export const validateAttributeInfluenceTuning = (tuning: unknown): AttributeInfluenceTuning => {
  return AttributeInfluenceTuningSchema.parse(tuning);
};

export const validatePerformanceTuning = (tuning: unknown): PerformanceTuning => {
  return PerformanceTuningSchema.parse(tuning);
};

// Configuration validation utilities
export const isValidProcessingConfig = (config: unknown): boolean => {
  try {
    ProcessingConfigTuningSchema.parse(config);
    return true;
  } catch {
    return false;
  }
};

export const getProcessingConfigErrors = (config: unknown): string[] => {
  try {
    ProcessingConfigTuningSchema.parse(config);
    return [];
  } catch (error) {
    if (error instanceof z.ZodError) {
      return error.errors.map((err) => `${err.path.join('.')}: ${err.message}`);
    }
    return ['Unknown validation error'];
  }
};

// Default configurations for different use cases
export const getDefaultProductionConfig = () => ({
  performanceTuning: {
    parallelProcessingEnabled: true,
    maxParallelEmails: 20,
    emailBatchSize: 100,
    enableCaching: true,
