   372→    if (!config.processingConfig?.topLevelCategories) {
   373→      return errors;
   374→    }
   375→
   376→    // Validate category consistency
   377→    for (const [categoryName, category] of Object.entries(config.processingConfig.topLevelCategories)) {
   378→      // Validate subtypes
   379→      for (const [subtypeName, subtype] of Object.entries(category.subtypes)) {
   380→        if (subtype.derived && !subtype.derivationLogic) {
   381→          errors.push({
   382→            code: 'MISSING_DERIVATION_LOGIC',
   383→            message: `Derived subtype "${categoryName}.${subtypeName}" has no derivation logic`,
   384→            path: `topLevelCategories.${categoryName}.subtypes.${subtypeName}`,
   385→            severity: 'error',
   386→            category: 'logic',
