   396→  private async validateCrossReferences(config: CategoryConfiguration): Promise<{
   397→    errors: ValidationError[];
   398→    warnings: ValidationWarning[];
   399→    totalChecks: number;
   400→  }> {
   401→    const errors: ValidationError[] = [];
   402→    const warnings: ValidationWarning[] = [];
