   715→    for (const category of Object.values(config.processingConfig.topLevelCategories)) {
   716→      for (const subtype of Object.values(category.subtypes)) {
   717→        if (subtype.ruleBasedClassification) {
   718→          for (const rules of Object.values(subtype.ruleBasedClassification)) {
   719→            if (rules) {
