   965→
   966→    const definedAttributes = new Set(Object.keys(config.processingConfig.attributes.schema));
   967→
   968→    // Check that all attributes in bonus map are defined in schema
   969→    if (config.processingConfig.attributes.attributeBonusMap) {
   970→      for (const [categoryName, bonusMap] of Object.entries(config.processingConfig.attributes.attributeBonusMap)) {
   971→        for (const attributeName of Object.keys(bonusMap)) {
