   998→                path: `attributeRelevance.${categoryName}.categoryRoles.${attributeName}`,
   999→                severity: 'error',
  1000→                category: 'reference',
  1001→                suggestion: `Add "${attributeName}" to attributes.schema or remove from relevance matrix`,
  1002→              });
  1003→            }
  1004→          }
