     2→import type {
     3→  CategoryRuleResult,
     4→  ClassificationResult,
     5→  ClassificationSession,
     6→  EmailMessage,
     7→  RuleScoringMatch,
     8→  SubtypeDefinition,
     9→  SubtypeScore,
    10→  TopLevelCategory,
    11→} from '../types';
    12→import { RulePatternSchema } from '../config/category-config-schema';
    13→import { ensureCategoryScoreInitialized } from '../utils/initialization';
    14→import { matchRulePattern } from '../utils/rule-matcher';
    15→
    16→/**
    17→ * Rule-Based Scoring Stage
    18→ *
    19→ * Implements lexical pattern matching per SCORING_LOGIC.md "Subtype Scoring Formula" section.
    20→ * Applies rule-based classification patterns with bounded aggregation to prevent score inflation
    21→ * while allowing multiple patterns to contribute to category confidence.
    22→ *
    23→ * CANONICAL SIGNATURE: (email, session, result, config) => void
    24→ *
    25→ * Logic:
    26→ * - score(subtype) = sum(topK(highMatches, KHigh))
    27→ *                  + M_medium * sum(topK(mediumMatches, KMedium))
    28→ *                  + M_low * sum(topK(lowMatches, KLow))
    29→ *                  + attributeBonus(subtype)
    30→ * - Category score = primary + min(secondarySupport, secondarySupportCap)
    31→ * - Uses max of existing score vs aggregated rule score
    32→ * - Mutates result.explainabilityTrace and result.scoreBreakdown instead of returning
    33→ */
    34→
    35→export type SubtypeRuleClassification = NonNullable<SubtypeDefinition['ruleBasedClassification']>;
    36→
    37→export interface RuleScoringStageConfig {
    38→  // Configuration settings for rule scoring behavior
    39→  settings: {
    40→    useLexicalPatterns: boolean;
    41→    applySubtypeRules: boolean;
    42→    boundedAggregation: boolean;
    43→  };
    44→
    45→  // Top-level categories with their subtypes and rules
    46→  topLevelCategories: Record<string, TopLevelCategory>;
    47→
    48→  // Tuning parameters for subtype scoring formula
    49→  tuningParameters: {
    50→    KHigh: number; // Max high-confidence matches to consider
    51→    KMedium: number; // Max medium-confidence matches to consider
    52→    KLow: number; // Max low-confidence matches to consider
    53→    M_medium: number; // Multiplier for medium-confidence scores
    54→    M_low: number; // Multiplier for low-confidence scores
    55→    TAIL_DAMPEN: number; // Damping factor for secondary subtype support
    56→    TAIL_RATIO_CAP: number; // Max ratio of tail support to primary score
    57→  };
    58→}
    59→
    60→// Type re-exports for convenience (actual definitions in types/explainability-trace.ts)
    61→export type { CategoryRuleResult, RuleScoringMatch, SubtypeScore };
    62→
    63→export interface RuleScoringResult {
    64→  categoryResults: CategoryRuleResult[];
    65→  updatedScores: Record<string, number>;
    66→  totalMatches: number;
    67→  categoriesWithRules: number;
    68→  highestRuleScore: number;
    69→  processingDurationMs: number;
    70→}
    71→
    72→export const SubtypeRuleClassificationSchema = z.object({
    73→  highConfidence: z.array(RulePatternSchema).optional(),
    74→  mediumConfidence: z.array(RulePatternSchema).optional(),
    75→  lowConfidence: z.array(RulePatternSchema).optional(),
    76→});
    77→
    78→export const RuleScoringStageConfigSchema = z.object({
    79→  settings: z.object({
    80→    useLexicalPatterns: z.boolean(),
    81→    applySubtypeRules: z.boolean(),
    82→    boundedAggregation: z.boolean(),
    83→  }),
    84→  topLevelCategories: z.record(
    85→    z.object({
    86→      description: z.string(),
    87→      subtypes: z.record(
    88→        z.object({
    89→          description: z.string(),
    90→          ruleBasedClassification: SubtypeRuleClassificationSchema.optional(),
    91→          derived: z.boolean().optional(),
    92→          derivationLogic: z.string().optional(),
    93→        })
    94→      ),
    95→    })
    96→  ),
    97→  tuningParameters: z.object({
    98→    KHigh: z.number().int().min(1),
    99→    KMedium: z.number().int().min(1),
   100→    KLow: z.number().int().min(1),
   101→    M_medium: z.number().min(0).max(1),
   102→    M_low: z.number().min(0).max(1),
   103→    TAIL_DAMPEN: z.number().min(0).max(1),
   104→    TAIL_RATIO_CAP: z.number().min(0).max(1),
   105→  }),
   106→});
