   110→ *
   111→ * @param email - Email message to analyze for pattern matches
   112→ * @param session - Classification session batch metadata (canonical signature parameter, not used directly)
   113→ * @param result - Classification result to update (mutated in place)
   114→ * @param config - Rule scoring configuration with pattern hierarchies
   115→ */
   116→export function executeRuleScoring(
   117→  email: EmailMessage,
   118→  _session: ClassificationSession,
   119→  result: ClassificationResult,
   120→  config: RuleScoringStageConfig
   121→): void {
