   131→/**
   132→ * Classification Pipeline orchestrator
   133→ *
   134→ * Manages sequential execution of classification stages with proper context
   135→ * propagation, error handling, and performance tracking.
   136→ */
   137→export class ClassificationPipeline {
   138→  private readonly config: CategoryConfiguration;
   139→  private readonly testMode: boolean;
   140→  private readonly domainLookup: DomainLookup;
   141→
   142→  /**
   143→   * Initialize classification pipeline with validated configuration
   144→   *
   145→   * @param config - Complete category configuration including processingConfig
   146→   * @param testMode - If true, use timestamp-based session IDs for easier debugging
   147→   * @throws {Error} If configuration validation fails
   148→   */
   149→  constructor(config: CategoryConfiguration, testMode: boolean = false) {
   150→    // Validate processing configuration
   151→    validateConfigInput(config.processingConfig);
   152→
   153→    // Validate confidence thresholds specifically
   154→    const { confidenceThresholds } = config.processingConfig;
   155→    if (
   156→      !confidenceThresholds ||
   157→      confidenceThresholds.highConfidence < 0 ||
   158→      confidenceThresholds.mediumConfidence < 0 ||
   159→      confidenceThresholds.lowConfidence < 0 ||
   160→      confidenceThresholds.secondaryLabelMinGap < 0
   161→    ) {
   162→      throw new Error('Invalid confidence thresholds: all values must be non-negative');
   163→    }
   164→
   165→    this.config = config;
   166→    this.testMode = testMode;
   167→
   168→    // Load domain lookup from config/domain-sources.json
   169→    // Gracefully handles missing/malformed files by returning empty lookup
   170→    this.domainLookup = loadDomainLookup();
   171→  }
   172→
   173→  /**
   174→   * Get configuration (for testing and future stage integration)
   175→   */
   176→  getConfig(): CategoryConfiguration {
   177→    return this.config;
   178→  }
   179→
   180→  /**
   181→   * Helper function to determine if a stage should be skipped for replay
   182→   *
   183→   * @param stageName - Name of the current stage
   184→   * @param replayFromStage - Stage to start replay from (optional)
   185→   * @returns true if stage should be skipped, false to execute
   186→   */
   187→  private shouldSkipStage(stageName: string, replayFromStage?: string): boolean {
   188→    if (!replayFromStage) return false;
   189→    const replayIndex = STAGE_ORDER.indexOf(replayFromStage as (typeof STAGE_ORDER)[number]);
   190→    const currentIndex = STAGE_ORDER.indexOf(stageName as (typeof STAGE_ORDER)[number]);
   191→    return replayIndex !== -1 && currentIndex < replayIndex;
   192→  }
   193→
   194→  /**
   195→   * Stage configuration mapping for factory pattern
   196→   */
   197→  private readonly stageConfigs = {
   198→    'hard-assertions': () => this.getHardAssertionConfig(),
   199→    'strong-indicators': () => this.getStrongIndicatorConfig(),
   200→    'rule-scoring': () => this.getRuleScoringConfig(),
   201→    'attribute-detection': () => this.getAttributeDetectionConfig(),
   202→    'attribute-influence': () => this.config,
   203→    disambiguation: () => this.config,
   204→    'multi-label-selection': () => ({
   205→      multiLabel: this.getMultiLabelConfig(),
   206→      confidenceThresholds: this.getConfidenceThresholds(),
   207→    }),
   208→    'ai-routing': () => this.getAIRoutingConfig(),
   209→    'ai-feature-extraction': () => this.getAIFeatureExtractionConfig(),
   210→    'ai-classification': () => this.getAIClassificationConfig(),
   211→    'ai-label-filtering': () => this.getAILabelFilteringConfig(),
