   340→
   341→      // Create classification session for single email
   342→      const session = createClassificationSession(this.config.processingConfig, 'sequential', 1, this.testMode);
   343→
   344→      // Create classification result
   345→      const result = createClassificationResult(email.id, session.id, 0);
   346→
   347→      // Execute pipeline stages using shared logic
   348→      await this.executePipelineStages(email, session, result, pipelineStartTime, replayFromStage);
   349→
   350→      // Mark session as successful
   351→      incrementSessionSuccess(session);
   352→      finalizeClassificationSession(session);
   353→
   354→      // Update final processing time
   355→      result.processingDurationMs = Date.now() - pipelineStartTime;
   356→      result.processedAt = new Date();
   357→
   358→      return result;
   359→    } catch (error) {
   360→      throw this.createPipelineError(email, pipelineStartTime, error);
   361→    }
   362→  }
   363→
   364→  /**
   365→   * Execute classification pipeline using provided session (for batch processing)
   366→   *
   367→   * Uses an externally-created session to enable multiple emails to share the same
   368→   * sessionId. This is essential for batch processing where all emails should be
   369→   * grouped under one session for traceability.
