### HIGH PRIORITY ISSUES (Should fix before merge)

#### H1. Missing Cache Eviction Policy

**Location**: `classification-engine.ts:54-55` - Cache declarations

**Issue**:
```typescript
private readonly configCache = new Map<string, CategoryConfiguration>();
private readonly pipelineCache = new Map<string, ClassificationPipeline>();
```

**Root Cause**: Unbounded cache growth - no TTL, LRU, or size limits

**Impact**: 
- Memory leak in long-running processes
- Cache never invalidates even when configs change on disk
- Pipeline cache holds compiled state indefinitely

**Recommendation**:
```typescript
// Add cache metadata
interface CacheEntry<T> {
  value: T;
  timestamp: number;
  accessCount: number;
}

private readonly configCache = new Map<string, CacheEntry<CategoryConfiguration>>();
private readonly cacheTtlMs = 5 * 60 * 1000; // 5 minutes
private readonly maxCacheSize = 10; // Max config versions

private getCachedConfig(cacheKey: string): CategoryConfiguration | undefined {
  const entry = this.configCache.get(cacheKey);
  if (!entry) return undefined;

  // Check TTL
  if (Date.now() - entry.timestamp > this.cacheTtlMs) {
    this.configCache.delete(cacheKey);
    this.pipelineCache.delete(cacheKey);
    return undefined;
  }

  entry.accessCount++;
  return entry.value;
}

private setCachedConfig(cacheKey: string, config: CategoryConfiguration): void {
  // Evict LRU if at capacity
  if (this.configCache.size >= this.maxCacheSize) {
    const lruKey = this.findLRUKey();
    this.configCache.delete(lruKey);
    this.pipelineCache.delete(lruKey);
  }

  this.configCache.set(cacheKey, {
    value: config,
    timestamp: Date.now(),
    accessCount: 1,
  });
}
```

**Priority**: P1 - Production stability

