import { ConfigurationValidator } from '../../../src/config/config-validator';
import {
  createTestCategoryConfig,
  validMinimalCategoryConfig,
} from '../../fixtures/configs/valid-minimal-category-config';

describe('ConfigurationValidator helper utilities', () => {
  let validator: ConfigurationValidator;

  beforeEach(() => {
    validator = new ConfigurationValidator();
  });

  describe('parseValidationError', () => {
    it('parses JSON formatted Zod error strings', () => {
      const jsonError = JSON.stringify([
        {
          code: 'invalid_type',
          message: 'Expected number, received string',
          path: ['processingConfig', 'version'],
        },
      ]);

      const parsed = validator.parseValidationError(jsonError);

      expect(parsed).toEqual({
        code: 'invalid_type',
        message: 'Expected number, received string',
        path: 'processingConfig.version',
        severity: 'error',
        category: 'schema',
      });
    });

    it('falls back to heuristic parsing for known string patterns', () => {
      const parsed = validator.parseValidationError('processingConfig.confidenceThresholds.highConfidence exceeds 1.5');

      expect(parsed.code).toBe('INVALID_RANGE');
      expect(parsed.path).toBe('processingConfig.confidenceThresholds.highConfidence');
      expect(parsed.severity).toBe('error');
      expect(parsed.category).toBe('schema');
    });
  });

  describe('detectRuleConflicts', () => {
    it('flags duplicate hard assertion subject prefixes across categories', () => {
      const baseProcessing = validMinimalCategoryConfig.processingConfig;

      const configWithConflicts = createTestCategoryConfig({
        processingConfig: {
          ...baseProcessing,
          categorySignals: {
            financial: {
              hardAssertions: {
                subjectPrefixes: ['Invoice:'],
              },
              strongIndicators: {
                subjectContains: ['invoice'],
              },
            },
            operations: {
              hardAssertions: {
                subjectPrefixes: ['Invoice:'],
              },
              strongIndicators: {
                subjectContains: ['operations'],
              },
            },
          },
          topLevelCategories: {
            financial: {
              description: 'Financial communications',
              subtypes: {
                receipt: {
                  description: 'Receipts',
                  derived: false,
                  parallelSafe: true,
                },
              },
              aiFinalClassification: {
                categoryDescription: 'Financial category',
                decisionCriteria: ['Contains billing language'],
              },
            },
            operations: {
              description: 'Operations communications',
              subtypes: {
                ops_update: {
                  description: 'Ops updates',
                  derived: false,
                  parallelSafe: true,
                },
              },
              aiFinalClassification: {
                categoryDescription: 'Operations category',
                decisionCriteria: ['Contains operational language'],
              },
            },
          },
          attributeRelevance: {
            RolesLegend: baseProcessing.attributeRelevance.RolesLegend,
            financial: { categoryRoles: {} },
            operations: { categoryRoles: {} },
          },
        },
      });

      const errors = validator.detectRuleConflicts(configWithConflicts);

      expect(errors).toHaveLength(1);
      expect(errors[0].code).toBe('RULE_CONFLICT');
      expect(errors[0].path).toBe('categorySignals.hardAssertions.subjectPrefixes');
    });
  });

  describe('validateAttributeMatrix', () => {
    it('identifies attribute references that are not defined in the schema', () => {
      const baseProcessing = validMinimalCategoryConfig.processingConfig;

      const configWithMissingAttributes = createTestCategoryConfig({
        processingConfig: {
          ...baseProcessing,
          attributes: {
            ...baseProcessing.attributes,
            schema: {
              definedAttribute: {
                type: 'boolean',
                description: 'A defined attribute',
              },
            },
            attributeBonusMap: {
              financial: {
                missingAttribute: 0.5,
              },
            },
          },
          attributeRelevance: {
            RolesLegend: baseProcessing.attributeRelevance.RolesLegend,
            financial: {
              categoryRoles: {
                missingAttribute: 'CORE',
              },
            },
          },
        },
      });

      const errors = validator.validateAttributeMatrix(configWithMissingAttributes);

      expect(errors).toHaveLength(2);
      const paths = errors.map((error) => error.path);
      expect(paths).toContain('attributes.attributeBonusMap.financial.missingAttribute');
      expect(paths).toContain('attributeRelevance.financial.categoryRoles.missingAttribute');
    });
  });
});

