import { validateDomainSources, DomainSourcesSchema } from '../../../src/config/domain-sources-schema';

describe('DomainSourcesSchema', () => {
  describe('validateDomainSources', () => {
    it('should accept valid domain sources with high confidence', () => {
      const validConfig = {
        financial: {
          domains: [
            { domain: 'chase.com', type: 'bank', confidence: 'high' },
            { domain: 'wellsfargo.com', type: 'bank', confidence: 'high' },
          ],
          notes: 'Financial institutions',
        },
      };

      expect(() => validateDomainSources(validConfig)).not.toThrow();
      const result = validateDomainSources(validConfig);
      expect(result.financial.domains).toHaveLength(2);
      expect(result.financial.domains[0].confidence).toBe('high');
    });

    it('should accept valid domain sources with medium confidence', () => {
      const validConfig = {
        logistics: {
          domains: [{ domain: 'fedex.com', type: 'carrier', confidence: 'medium' }],
        },
      };

      expect(() => validateDomainSources(validConfig)).not.toThrow();
      const result = validateDomainSources(validConfig);
      expect(result.logistics.domains[0].confidence).toBe('medium');
    });

    it('should accept valid domain sources with low confidence', () => {
      const validConfig = {
        newsletter: {
          domains: [{ domain: 'example.com', confidence: 'low' }],
          notes: 'Low confidence newsletters',
        },
      };

      expect(() => validateDomainSources(validConfig)).not.toThrow();
      const result = validateDomainSources(validConfig);
      expect(result.newsletter.domains[0].confidence).toBe('low');
    });

    it('should accept valid domain sources without type field', () => {
      const validConfig = {
        newsletter: {
          domains: [{ domain: 'medium.com', confidence: 'high' }],
        },
      };

      expect(() => validateDomainSources(validConfig)).not.toThrow();
      const result = validateDomainSources(validConfig);
      expect(result.newsletter.domains[0].type).toBeUndefined();
    });

    it('should accept valid domain sources without notes field', () => {
      const validConfig = {
        logistics: {
          domains: [{ domain: 'ups.com', type: 'carrier', confidence: 'high' }],
        },
      };

      expect(() => validateDomainSources(validConfig)).not.toThrow();
      const result = validateDomainSources(validConfig);
      expect(result.logistics.notes).toBeUndefined();
    });

    it('should reject invalid confidence value - arbitrary string', () => {
      const invalidConfig = {
        financial: {
          domains: [{ domain: 'chase.com', type: 'bank', confidence: 'very-high' }],
          notes: 'Invalid confidence',
        },
      };

      expect(() => validateDomainSources(invalidConfig)).toThrow();
    });

    it('should reject invalid confidence value - typo', () => {
      const invalidConfig = {
        financial: {
          domains: [{ domain: 'chase.com', type: 'bank', confidence: 'hight' }],
          notes: 'Typo in confidence',
        },
      };

      expect(() => validateDomainSources(invalidConfig)).toThrow();
    });

    it('should reject missing confidence field', () => {
      const invalidConfig = {
        financial: {
          domains: [{ domain: 'chase.com', type: 'bank' }],
          notes: 'Missing confidence',
        },
      };

      expect(() => validateDomainSources(invalidConfig)).toThrow();
    });

    it('should reject missing domain field', () => {
      const invalidConfig = {
        financial: {
          domains: [{ type: 'bank', confidence: 'high' }],
          notes: 'Missing domain',
        },
      };

      expect(() => validateDomainSources(invalidConfig)).toThrow();
    });

    it('should reject non-array domains field', () => {
      const invalidConfig = {
        financial: {
          domains: 'not-an-array',
          notes: 'Invalid domains type',
        },
      };

      expect(() => validateDomainSources(invalidConfig)).toThrow();
    });

    it('should accept multiple categories with mixed confidence levels', () => {
      const validConfig = {
        financial: {
          domains: [
            { domain: 'chase.com', type: 'bank', confidence: 'high' },
            { domain: 'paypal.com', type: 'payment_processor', confidence: 'medium' },
          ],
          notes: 'Financial institutions',
        },
        logistics: {
          domains: [
            { domain: 'fedex.com', type: 'carrier', confidence: 'high' },
            { domain: 'amazon.com', type: 'marketplace', confidence: 'low' },
          ],
          notes: 'Shipping and logistics',
        },
      };

      expect(() => validateDomainSources(validConfig)).not.toThrow();
      const result = validateDomainSources(validConfig);
      expect(Object.keys(result)).toHaveLength(2);
      expect(result.financial.domains).toHaveLength(2);
      expect(result.logistics.domains).toHaveLength(2);
    });
  });

  describe('DomainSourcesSchema direct usage', () => {
    it('should provide proper type inference', () => {
      const validConfig = {
        financial: {
          domains: [{ domain: 'chase.com', type: 'bank', confidence: 'high' as const }],
          notes: 'Financial institutions',
        },
      };

      const result = DomainSourcesSchema.parse(validConfig);

      // Type assertion to verify proper inference
      const confidence: 'high' | 'medium' | 'low' = result.financial.domains[0].confidence;
      expect(confidence).toBe('high');
    });
  });
});

